package qa.controllStatement;

public class If {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int a,b;
		
		a=5;
		b=8;
		
		
		// checking condition 
		if (a==b) {
			System.out.println("condition true");
		}
		else {
			System.out.println("condition false");
		}

	}

}
